findings.codeql_raw_query:
/**
 * @name Cross-site scripting (XSS) via template rendering
 * @description User input rendered in templates without proper escaping can lead to XSS
 * @kind path-problem
 * @problem.severity error
 * @id py/xss-template
 * @tags security
 *        external/cwe/cwe-079
 */

import python
import semmle.python.dataflow.new.DataFlow
import semmle.python.dataflow.new.TaintTracking
import semmle.python.dataflow.new.RemoteFlowSources
import semmle.python.ApiGraphs

module XSSConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    exists(DataFlow::CallCfgNode call |
      call = API::moduleImport("django").getMember("utils").getMember("safestring").getMember("mark_safe").getACall() and
      sink = call.getArg(0)
    )
  }
}

module XSSFlow = TaintTracking::Global<XSSConfig>;
import XSSFlow::PathGraph

from XSSFlow::PathNode source, XSSFlow::PathNode sink
where XSSFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Potential XSS via mark_safe from $@.", source.getNode(), "user input"
